class Solution {
    public int minimumDeleteSum(String s1, String s2) {
        int sum = 0;
        int i = 0, j = 0;
        while (i < s1.length() || j < s2.length()) {
            if (i < s1.length() && j < s2.length()) {
                if (s1.charAt(i) == s2.charAt(j)) {
                    i++;
                    j++;
                } else {
                    sum += s1.charAt(i) < s2.charAt(j) ? s1.charAt(i++) : s2.charAt(j++);
                }
            } else if (i < s1.length()) {
                sum += s1.charAt(i++);
            } else {
                sum += s2.charAt(j++);
            }
        }
        return sum;
    }
}
